function creativeAction(id, type, label, options = {}) {
  return {
    id,
    type,
    label,
    summary: options.summary || '',
    tool: options.tool || '',
    riskLevel: Math.max(1, Math.min(4, Number(options.riskLevel || 2))),
    safeToAutoRun: Boolean(options.safeToAutoRun),
    requires: Array.isArray(options.requires) ? options.requires : [],
    confirmationRequired: Boolean(options.confirmationRequired),
    instruction: options.instruction || '',
    args: options.args || {},
    steps: options.steps || undefined,
  };
}

function creativeStageActionPack({ intent, stageId, selectedApp, instruction }) {
  const stage = creativeStageDefinition(intent, stageId);
  const appName = selectedApp?.name || 'creative app';
  const riskLevel = creativeStageRiskLevel(stageId);
  const hint = creativeAppStageHint(selectedApp, stageId);
  const actions = [
    creativeAction('open_app', 'app_workflow', `打开/聚焦 ${appName}`, {
      tool: 'run_app_workflow',
      riskLevel: 2,
      safeToAutoRun: true,
      summary: '低风险：只打开或聚焦创作软件。',
      steps: [
        { type: 'open_app', app: appName, label: `Open ${appName}` },
        { type: 'wait', ms: 1200, label: 'Wait for creative app' },
      ],
    }),
    creativeAction('observe_project', 'observe', '观察当前工程窗口', {
      tool: 'observe_now',
      riskLevel: 1,
      safeToAutoRun: true,
      summary: '读取当前 App、屏幕和 Accessibility 树，确认下一步目标。',
      args: { captureScreen: 'auto', includeAccessibility: true, maxNodes: 180, maxDepth: 8 },
    }),
  ];

  if (stageId === 'brief') {
    actions.push(
      creativeAction('collect_brief', 'prompt', '补齐创作 brief', {
        riskLevel: 1,
        summary: intent === 'music_compose'
          ? '确认风格、BPM、key、时长、参考曲和交付格式。'
          : '确认平台、比例、时长、素材路径、参考风格和导出格式。',
        requires: ['style', 'duration', 'deliverable'],
      }),
      creativeAction('save_brief', 'inbox', '把 brief 存到 Inbox/会话', {
        tool: 'capture_inbox_item',
        riskLevel: 1,
        summary: '把创作约束存成本地待办，方便后台或下次继续。',
      }),
    );
  } else if (stageId === 'import') {
    actions.push(
      creativeAction('inspect_assets', 'file_workflow', '检查素材文件夹', {
        tool: 'run_file_workflow',
        riskLevel: 1,
        summary: '列出素材目录，确认视频、音频、图片、字幕等文件存在。',
        requires: ['assetPath'],
        args: { intent: 'list' },
      }),
      creativeAction('open_import_ui', 'current_app_control', '打开导入素材入口', {
        tool: 'control_current_app',
        riskLevel: 3,
        summary: hint,
        confirmationRequired: true,
        instruction: `在 ${appName} 里打开导入素材/Import Media 入口，但不要确认覆盖或移动文件。`,
      }),
    );
  } else if (stageId === 'rough_cut') {
    actions.push(
      creativeAction('observe_timeline', 'observe', '观察时间线和选中片段', {
        tool: 'observe_now',
        riskLevel: 1,
        safeToAutoRun: true,
        summary: '确认 playhead、timeline、片段和当前工具状态。',
      }),
      creativeAction('make_cut_plan', 'plan_ui_action', '规划一次粗剪动作', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: hint,
        instruction: `只规划 ${appName} 里一次可撤销的粗剪/移动片段动作，不执行。`,
      }),
      creativeAction('execute_one_cut', 'current_app_control', '执行一次已确认剪切/移动', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: '只有目标片段和操作明确后才执行，并在执行后重新观察。',
      }),
    );
  } else if (stageId === 'polish') {
    actions.push(
      creativeAction('plan_caption_or_transition', 'plan_ui_action', '规划字幕/转场/标题动作', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: hint,
        instruction: `只规划 ${appName} 里添加字幕、标题或转场的下一步，不执行。`,
      }),
      creativeAction('apply_polish_step', 'current_app_control', '应用一个已确认修饰动作', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: '一次只应用一个字幕、标题、转场或特效，并观察结果。',
      }),
    );
  } else if (stageId === 'grade') {
    actions.push(
      creativeAction('open_adjustment_panel', 'current_app_control', '打开调色/音频面板', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: hint,
        instruction: `在 ${appName} 中打开调色或音频调整面板，但不要导出或覆盖文件。`,
      }),
      creativeAction('verify_preview', 'observe', '复查预览画面/音量', {
        tool: 'observe_now',
        riskLevel: 1,
        safeToAutoRun: true,
        summary: '调整后重新观察画面、面板和时间线状态。',
      }),
    );
  } else if (stageId === 'sound') {
    actions.push(
      creativeAction('open_sound_library', 'current_app_control', '打开音色/乐器库', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: hint,
        instruction: `在 ${appName} 中打开音色库或新建乐器轨，不录音、不覆盖工程。`,
      }),
      creativeAction('choose_sound_plan', 'plan_ui_action', '规划音色选择', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: '先规划目标音色或乐器轨选择，不执行。',
      }),
    );
  } else if (stageId === 'sketch') {
    actions.push(
      creativeAction('confirm_tempo_key', 'prompt', '确认 BPM/key/小节长度', {
        riskLevel: 1,
        summary: '录入 MIDI 或 loop 前确认速度、调性、长度和参考。',
        requires: ['bpm', 'key', 'bars'],
      }),
      creativeAction('plan_midi_entry', 'plan_ui_action', '规划一次 MIDI/loop 草稿动作', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: hint,
        instruction: `只规划 ${appName} 中创建短 MIDI/loop 草稿的下一步，不执行。`,
      }),
      creativeAction('enter_short_sketch', 'current_app_control', '执行一个已确认草稿动作', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: '一次只执行一个明确的 MIDI、loop 或录音准备动作。',
      }),
    );
  } else if (stageId === 'arrange') {
    actions.push(
      creativeAction('observe_sections', 'observe', '观察段落/小节/region', {
        tool: 'observe_now',
        riskLevel: 1,
        safeToAutoRun: true,
        summary: '确认当前段落、region、clip 或小节位置。',
      }),
      creativeAction('plan_arrangement_move', 'plan_ui_action', '规划一次编排移动/复制', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: hint,
        instruction: `只规划 ${appName} 里一次段落、clip 或 region 的移动/复制，不执行。`,
      }),
    );
  } else if (stageId === 'mix') {
    actions.push(
      creativeAction('open_mixer', 'current_app_control', '打开混音器/轨道控制', {
        tool: 'control_current_app',
        riskLevel: 3,
        confirmationRequired: true,
        summary: hint,
        instruction: `在 ${appName} 中打开 mixer/track controls，只做预览性调整。`,
      }),
      creativeAction('verify_mix', 'observe', '观察电平和效果状态', {
        tool: 'observe_now',
        riskLevel: 1,
        safeToAutoRun: true,
        summary: '调整后重新观察电平、轨道和插件状态。',
      }),
    );
  } else if (stageId === 'export') {
    actions.push(
      creativeAction('open_export_panel', 'current_app_control', '打开导出/分享面板', {
        tool: 'control_current_app',
        riskLevel: 4,
        confirmationRequired: true,
        summary: hint,
        requires: ['format', 'destinationPath', 'overwriteConfirmation'],
        instruction: `只打开 ${appName} 的导出/分享面板，不开始导出、不覆盖文件。`,
      }),
      creativeAction('verify_export_settings', 'prompt', '确认导出设置', {
        riskLevel: 4,
        confirmationRequired: true,
        summary: '确认格式、分辨率/采样率、范围、路径、文件名和覆盖策略。',
        requires: ['format', 'destinationPath', 'fileName'],
      }),
    );
  } else {
    actions.push(
      creativeAction('plan_current_step', 'plan_ui_action', '规划当前创作软件下一步', {
        tool: 'plan_ui_action',
        riskLevel: 2,
        summary: hint,
        instruction: `观察 ${appName} 后只规划下一步，不执行。`,
      }),
    );
  }

  return {
    id: stageId,
    label: stage?.label || stageId,
    summary: stage?.summary || '',
    intent,
    app: selectedApp?.name || '',
    riskLevel,
    hint,
    actions,
    safeAutoActionIds: actions.filter((action) => action.safeToAutoRun).map((action) => action.id),
    confirmationActionIds: actions.filter((action) => action.confirmationRequired).map((action) => action.id),
  };
}

function formatCreativeWorkflowOutput(result) {
  const appLabel = result.selectedApp?.name || '未选择';
  const installedLabel = result.selectedApp?.installed
    ? `已检测到 ${result.selectedApp.appPath}`
    : '未在常见位置检测到；仍可尝试用 macOS 打开应用名。';
  const stageLines = result.stages.map((stage, index) => `${index + 1}. ${stage.label}: ${stage.summary}`);
  const actionLines = result.actionPack?.actions?.length
    ? result.actionPack.actions
      .slice(0, 5)
      .map((action, index) => `${index + 1}. L${action.riskLevel} ${action.label}${action.tool ? ` -> ${action.tool}` : ''}${action.safeToAutoRun ? ' (可自动)' : action.confirmationRequired ? ' (需确认)' : ''}`)
      .join('\n')
    : '';
  return [
    `创作工作流: ${result.intent} · ${appLabel}`,
    `软件: ${installedLabel}`,
    `阶段:\n${stageLines.join('\n')}`,
    result.focusedStage ? `焦点阶段: ${result.focusedStage.label}` : '',
    actionLines ? `动作包:\n${actionLines}` : '',
    result.appRun?.output ? `本地操作:\n${result.appRun.output}` : '',
    result.observation?.output ? `观察:\n${result.observation.output}` : '',
    `下一步: ${result.nextActions[0] || '确认要使用的软件和素材位置。'}`,
  ].filter(Boolean).join('\n');
}

async function planCreativeWorkflow(options = {}) {
  const instruction = String(options.instruction || options.goal || options.task || '').trim();
  if (!instruction) throw new Error('Creative workflow requires instruction.');
  const intent = normalizeCreativeWorkflowIntent(options.intent, instruction);
  const candidates = creativeAppCandidates(instruction, intent, options.app || options.application || '');
  const selectedApp =
    candidates.find((item) => item.requested) ||
    candidates.find((item) => item.explicit && item.installed) ||
    candidates.find((item) => item.explicit) ||
    candidates.find((item) => item.installed) ||
    candidates[0] ||
    null;
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const stages = creativeWorkflowStages(intent);
  const focusedStageId = normalizeCreativeStageId(options.stage || options.phase || options.step, intent, instruction);
  const focusedStage = creativeStageDefinition(intent, focusedStageId);
  const actionPacks = stages.map((stage) => creativeStageActionPack({
    intent,
    stageId: stage.id,
    selectedApp,
    instruction,
  }));
  const actionPack = actionPacks.find((pack) => pack.id === focusedStageId) || actionPacks[0] || null;
  const nextActions = [
    selectedApp
      ? `${focusedStage?.label || '下一阶段'}: ${actionPack?.actions?.[0]?.label || `打开/聚焦 ${selectedApp.name}`}，然后观察工程窗口。`
      : '先指定要使用的剪辑或编曲软件。',
    '确认素材、工程位置、成品规格和是否允许保存/导出。',
    '复杂编辑不盲点界面；每次点击、输入、导出都通过现有本地动作策略执行。',
  ];
  let appRun = null;
  let observation = null;

  if (execute && selectedApp?.name) {
    appRun = await runAppWorkflow({
      title: `Open creative app · ${selectedApp.name}`,
      instruction,
      execute: true,
      source: 'creative_workflow',
      steps: [
        { type: 'open_app', app: selectedApp.name, label: `Open ${selectedApp.name}` },
        { type: 'wait', ms: Math.max(500, Math.min(5000, Number(options.waitMs || 1400))), label: 'Wait for creative app' },
      ],
      continueOnError: false,
    });
    if (appRun.ok && options.observeAfterOpen !== false) {
      const observed = await observeNow({
        source: 'creative_workflow',
        captureScreen: 'auto',
        includeAccessibility: true,
        screenMaxAgeMs: 8000,
        accessibilityMaxAgeMs: 4000,
        maxNodes: 180,
        maxDepth: 8,
      });
      observation = {
        ok: observed.ok,
        output: formatObservationForLocalCommand(observed),
        mac: observed.mac,
        screen: observed.screen,
        accessibility: observed.accessibility,
        errors: observed.errors,
      };
    }
  }

  const draft = {
    ok: Boolean(selectedApp) && (!execute || Boolean(appRun?.ok)),
    executed: execute,
    intent,
    selectedApp,
    candidates,
    stages,
    focusedStage,
    actionPacks,
    actionPack,
    nextActions,
    appRun,
    observation,
  };
  const output = formatCreativeWorkflowOutput(draft);
  const workflowDraft = {
    kind: 'creative',
    source: 'creative_workflow',
    status: execute && appRun && !appRun.ok ? 'blocked' : 'done',
    title: `Creative workflow · ${selectedApp?.name || intent}`,
    intent,
    mode: execute ? 'local' : 'preview',
    request: instruction,
    result: output,
    target: {
      app: selectedApp?.name || '',
      appId: selectedApp?.id || '',
      appDomain: selectedApp?.domain || creativeWorkflowDomain(intent),
      appInstalled: Boolean(selectedApp?.installed),
      appPath: selectedApp?.appPath || '',
      candidateCount: candidates.length,
      stageCount: stages.length,
      focusedStageId,
      actionCount: actionPack?.actions?.length || 0,
      appWorkflowId: appRun?.workflow?.id || '',
    },
  };
  const workflow = options.recordWorkflow === false
    ? {
        id: '',
        ...workflowDraft,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        completedAt: Date.now(),
      }
    : createWorkflowRecord(workflowDraft);
  const routing = options.recordRouting === false || !workflow.id
    ? null
    : createRoutingRecordForWorkflow({
        workflow,
        mode: 'local',
        source: options.source || 'creative_workflow',
        owner: 'app',
        scope: `creative:${intent}`,
        parallelGroup: options.parallelGroup || options.group || `creative:${selectedApp?.domain || intent}`,
        resultSummary: output,
      });

  return {
    ...draft,
    workflow,
    routing,
    output,
  };
}

function creativeActionIdFromOptions(options = {}, actionPack = null) {
  const requested = String(options.actionId || options.action || options.actionName || options.id || '').trim();
  if (requested) return requested;
  if (options.execute === true || String(options.execute || '').toLowerCase() === 'true') {
    return actionPack?.safeAutoActionIds?.[0] || actionPack?.actions?.[0]?.id || '';
  }
  return actionPack?.actions?.[0]?.id || '';
}

function creativeActionRequiresConfirmation(action) {
  if (!action) return false;
  if (action.confirmationRequired) return true;
  return Number(action.riskLevel || 0) >= 4;
}

function creativeActionConfirmationSatisfied(options = {}) {
  return options.confirm === true || options.confirmed === true || String(options.confirm || options.confirmed || '').toLowerCase() === 'true';
}

function formatCreativeActionExecutionOutput(result) {
  const action = result.action || {};
  const verification = result.verification || null;
  const recoveryHints = verification?.recoveryHints || [];
  return [
    `创作动作: ${action.id || 'unknown'} · ${action.label || ''}`,
    `状态: ${result.status}${result.executed ? ' · executed' : ' · preview'}`,
    result.requiresConfirmation ? '需要确认: 是' : '',
    result.missingRequirements?.length ? `缺少信息: ${result.missingRequirements.join(', ')}` : '',
    verification ? `验收: ${verification.status} · ${verification.summary}` : '',
    recoveryHints.length ? `补救:\n${recoveryHints.map((hint, index) => `${index + 1}. ${hint}`).join('\n')}` : '',
    result.result?.output ? `结果:\n${compactRecordText(result.result.output, 900)}` : '',
    result.output && !result.result?.output ? result.output : '',
  ].filter(Boolean).join('\n');
}

async function executeCreativeAction(action, options = {}) {
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  if (!execute) {
    return {
      ok: true,
      executed: false,
      status: 'preview',
      output: `${action.label}: ${action.summary || 'Prepared creative action preview.'}`,
    };
  }

  if (action.type === 'app_workflow') {
    const result = await runAppWorkflow({
      title: `creative action · ${action.label}`,
      instruction: options.instruction || action.summary || action.label,
      execute: true,
      source: 'creative_action',
      steps: action.steps || [],
      continueOnError: false,
    });
    return {
      ok: result.ok,
      executed: true,
      status: result.ok ? 'done' : 'blocked',
      result,
      output: result.output,
    };
  }

  if (action.type === 'observe') {
    const observed = await observeNow({
      ...(action.args || {}),
      source: 'creative_action',
      captureScreen: action.args?.captureScreen ?? 'auto',
      includeAccessibility: action.args?.includeAccessibility ?? true,
      screenMaxAgeMs: 8000,
      accessibilityMaxAgeMs: 4000,
      maxNodes: action.args?.maxNodes || options.maxNodes || 180,
      maxDepth: action.args?.maxDepth || options.maxDepth || 8,
    });
    const output = formatObservationForLocalCommand(observed);
    return {
      ok: observed.ok,
      executed: true,
      status: observed.ok ? 'done' : 'blocked',
      result: {
        ok: observed.ok,
        output,
        mac: observed.mac,
        screen: observed.screen,
        accessibility: observed.accessibility,
        errors: observed.errors,
      },
      output,
    };
  }

  if (action.type === 'file_workflow') {
    const targetPath = String(options.assetPath || options.path || options.folder || '').trim();
    if (!targetPath) {
      return {
        ok: false,
        executed: false,
        status: 'blocked',
        missingRequirements: ['assetPath'],
        output: '需要素材文件夹路径后才能检查素材。',
      };
    }
    const result = await runFileWorkflow({
      path: targetPath,
      intent: action.args?.intent || 'list',
      instruction: options.instruction || action.summary || action.label,
      mode: 'quick',
      source: 'creative_action',
      scope: `creative:${options.intent || 'creative'}:${action.id}`,
      parallelGroup: options.parallelGroup || options.group || 'creative:file',
    });
    return {
      ok: result.ok,
      executed: true,
      status: result.ok ? 'done' : 'blocked',
      result,
      output: result.output,
    };
  }

  if (action.type === 'plan_ui_action') {
    const result = await accessibilityActionPlan({
      instruction: String(options.actionInstruction || action.instruction || action.summary || action.label),
      maxNodes: options.maxNodes || 180,
      maxDepth: options.maxDepth || 8,
    });
    return {
      ok: result.ok,
      executed: false,
      status: result.ok ? 'done' : 'blocked',
      result,
      output: result.output || result.recommended?.summary || 'UI action plan generated.',
    };
  }

  if (action.type === 'current_app_control') {
    const result = await controlCurrentApp({
      instruction: String(options.actionInstruction || action.instruction || action.summary || action.label),
      content: options.content ?? options.value,
      execute: true,
      recordWorkflow: false,
      maxNodes: options.maxNodes || 180,
      maxDepth: options.maxDepth || 8,
      approvalContext: {
        workflowId: options.workflowId || '',
        title: `creative action · ${action.label}`,
        instruction: options.instruction || action.instruction || action.label,
        source: 'creative_action',
      },
    });
    return {
      ok: result.ok,
      executed: Boolean(result.executed),
      status: result.ok ? 'done' : result.approval ? 'approval_required' : 'blocked',
      approval: result.approval,
      result,
      output: result.output,
    };
  }

  if (action.type === 'inbox') {
    const body = String(options.body || options.text || options.instruction || '').trim();
    if (!body) {
      return {
        ok: false,
        executed: false,
        status: 'blocked',
        missingRequirements: ['body'],
        output: '需要 brief 文本后才能保存到 Inbox。',
      };
    }
    const item = createInboxItem({
      title: options.title || action.label,
      body,
      source: 'creative_action',
      priority: options.priority || 2,
      tags: ['creative', options.intent || 'creative'].filter(Boolean),
    });
    return {
      ok: true,
      executed: true,
      status: 'done',
      result: { item, counts: inboxCounts() },
      output: `已保存到 Inbox: ${item.title}`,
    };
  }

  return {
    ok: false,
    executed: false,
    status: 'blocked',
    output: `${action.type} 动作需要用户补充信息或暂不支持自动执行。`,
  };
}

function creativeActionVerificationEnabled(options = {}, execute = false) {
  const value = options.verify;
  if (value === false || String(value || '').toLowerCase() === 'false') return false;
  if (value === true || String(value || '').toLowerCase() === 'true') return true;
  return Boolean(execute);
}

function creativeActionExpectedAppMatches(actualApp, expectedApp) {
  const actual = normalizedCreativeMatchText(actualApp);
  const expected = normalizedCreativeMatchText(expectedApp);
  if (!actual || !expected) return null;
  const compactActual = actual.replace(/\s+/g, '');
  const compactExpected = expected.replace(/\s+/g, '');
  return (
    actual === expected ||
    actual.includes(expected) ||
    expected.includes(actual) ||
    compactActual.includes(compactExpected) ||
    compactExpected.includes(compactActual)
  );
}

function creativeActionExpectsCreativeApp(action) {
  return ['app_workflow', 'observe', 'plan_ui_action', 'current_app_control'].includes(action?.type);
}

function creativeActionVerificationSignals(action, plan, observation = null) {
  const mac = observation?.mac || {};
  const frontmost = mac.frontmost || {};
  const accessibility = observation?.accessibility || {};
  const expectedApp = plan?.selectedApp?.name || '';
  const frontmostApp = frontmost.app || accessibility.app || '';
  const expectsCreativeApp = creativeActionExpectsCreativeApp(action);
  const frontmostMatchesExpected = expectsCreativeApp
    ? creativeActionExpectedAppMatches(frontmostApp, expectedApp)
    : null;
  return {
    actionId: action?.id || '',
    actionType: action?.type || '',
    expectedApp,
    frontmostApp,
    windowTitle: frontmost.windowTitle || accessibility.windowTitle || '',
    frontmostMatchesExpected,
    screenAvailable: Boolean(observation?.screen),
    accessibilityAvailable: Boolean(accessibility?.available),
    accessibilityNodeCount: Number(accessibility?.nodeCount || 0),
    errors: Array.isArray(observation?.errors) ? observation.errors : [],
  };
}

function creativeActionRecoveryHints(action, execution, plan, verification = null) {
  const hints = [];
  const actionId = action?.id || '';
  const selectedApp = plan?.selectedApp?.name || '目标创作软件';
  const add = (hint) => {
    const text = String(hint || '').trim();
    if (text && !hints.includes(text)) hints.push(text);
  };

  if (execution?.requiresConfirmation) {
    add(`确认目标无误后，重新运行 actionId:${actionId} 并传入 confirm:true。`);
  }

  for (const requirement of execution?.missingRequirements || []) {
    if (requirement === 'assetPath') add('补充素材文件夹路径 assetPath，再让它检查素材。');
    else if (requirement === 'body') add('补充 brief 文本 body/text，再保存到 Inbox。');
    else add(`补充缺少的信息: ${requirement}。`);
  }

  if (execution?.approval) {
    add('先在本地 approvals 队列里批准这一步，再继续剩余动作。');
  }

  if (action?.type === 'prompt' || action?.requires?.length) {
    add(`补齐 ${action.requires?.join(', ') || '创作 brief'} 后，再继续同一阶段。`);
  }

  if (action?.type === 'app_workflow' && execution?.ok === false) {
    add(`确认 ${selectedApp} 已安装并能手动打开；如果软件名不对，传入 app 指定正确应用。`);
  }

  if (action?.type === 'file_workflow' && !execution?.ok) {
    add('先提供可访问的本地素材目录，并保持素材检查为只读。');
  }

  if (['current_app_control', 'plan_ui_action'].includes(action?.type) && !execution?.ok) {
    add('先执行 observe_project 读取当前窗口，再执行对应的 plan_ui_action 缩小目标。');
    add('如果目标按钮/面板不清楚，用 actionInstruction 明确要点击或填写的 UI。');
  }

  if (verification?.signals?.frontmostMatchesExpected === false) {
    add(`先执行 open_app 聚焦 ${selectedApp}，确认前台窗口正确后再继续。`);
  }

  if (verification?.status === 'needs_review' && !verification?.signals?.accessibilityAvailable) {
    add('如果目标软件已在前台但 UI 树仍为空，再刷新 macOS Accessibility 权限后继续。');
  }

  if (!hints.length && verification?.status === 'needs_review') {
    add('重新观察屏幕和 UI 树，确认界面状态后再执行下一步。');
  }

  return hints.slice(0, 6);
}

async function verifyCreativeAction(action, execution, plan, options = {}) {
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  if (!creativeActionVerificationEnabled(options, execute)) return null;

  if (!execution?.executed) {
    const status = execution?.status === 'preview' ? 'preview' : execution?.approval ? 'approval_required' : 'blocked';
    const verification = {
      ok: Boolean(execution?.ok),
      status,
      summary: status === 'preview'
        ? '预览模式未执行动作。'
        : compactRecordText(execution?.output || '动作未执行，等待补充信息或确认。', 220),
      signals: creativeActionVerificationSignals(action, plan, null),
      output: '',
      recoveryHints: [],
    };
    verification.recoveryHints = creativeActionRecoveryHints(action, execution, plan, verification);
    return verification;
  }

  let observation = null;
  if (action?.type === 'observe' && execution.result) {
    observation = {
      ok: execution.result.ok,
      generatedAt: new Date().toISOString(),
      mac: execution.result.mac || {},
      screen: execution.result.screen || execution.result.mac?.screen || null,
      accessibility: execution.result.accessibility || null,
      errors: execution.result.errors || [],
    };
  } else {
    try {
      observation = await observeNow({
        source: 'creative_action_verify',
        captureScreen: 'auto',
        includeAccessibility: true,
        screenMaxAgeMs: 5000,
        accessibilityMaxAgeMs: 1500,
        maxNodes: options.verifyMaxNodes || options.maxNodes || 140,
        maxDepth: options.verifyMaxDepth || options.maxDepth || 7,
      });
    } catch (error) {
      observation = {
        ok: false,
        generatedAt: new Date().toISOString(),
        mac: {},
        screen: null,
        accessibility: null,
        errors: [error instanceof Error ? error.message : String(error)],
      };
    }
  }

  const signals = creativeActionVerificationSignals(action, plan, observation);
  let status = 'verified';
  if (!execution.ok) status = execution.approval ? 'approval_required' : 'blocked';
  else if (signals.frontmostMatchesExpected === false) status = 'needs_review';
  else if (signals.errors.length) status = 'needs_review';
  else if (action?.type === 'observe' && !signals.screenAvailable && !signals.accessibilityAvailable) status = 'needs_review';

  const summary = status === 'verified'
    ? signals.frontmostApp
      ? `已观察到 ${signals.frontmostApp}${signals.accessibilityAvailable ? `，UI ${signals.accessibilityNodeCount} nodes` : ''}。`
      : '动作执行后已完成复查。'
    : status === 'needs_review'
      ? `复查需要人工或下一步确认: ${signals.frontmostApp || '未识别前台 App'}。`
      : compactRecordText(execution.output || '动作未完成。', 220);

  const output = observation ? compactRecordText(formatObservationForLocalCommand(observation), 1200) : '';
  const verification = {
    ok: status === 'verified',
    status,
    summary,
    signals,
    output,
    recoveryHints: [],
  };
  verification.recoveryHints = creativeActionRecoveryHints(action, execution, plan, verification);
  return verification;
}

async function runCreativeWorkflowAction(options = {}) {
  const instruction = String(options.instruction || options.goal || options.task || '').trim();
  if (!instruction) throw new Error('Creative action requires instruction.');
  const execute = options.execute === true || String(options.execute || '').toLowerCase() === 'true';
  const plan = await planCreativeWorkflow({
    instruction,
    intent: options.intent,
    stage: options.stage || options.phase || options.step,
    app: options.app || options.application,
    execute: false,
    recordWorkflow: false,
    recordRouting: false,
    source: options.source || 'creative_action',
  });
  const actionId = creativeActionIdFromOptions(options, plan.actionPack);
  const action = (plan.actionPack?.actions || []).find((item) => item.id === actionId);
  if (!action) throw new Error(`Creative action not found: ${actionId || 'missing actionId'}.`);

  const confirmed = creativeActionConfirmationSatisfied(options);
  const requiresConfirmation = creativeActionRequiresConfirmation(action);
  let execution;
  if (requiresConfirmation && execute && !confirmed) {
    execution = {
      ok: false,
      executed: false,
      status: 'blocked',
      requiresConfirmation: true,
      output: `需要明确确认后才能执行: ${action.label}`,
    };
  } else {
    execution = await executeCreativeAction(action, {
      ...options,
      execute,
      intent: plan.intent,
    });
  }

  const verification = await verifyCreativeAction(action, execution, plan, {
    ...options,
    execute,
  });
  const outputDraft = {
    ok: execution.ok,
    executed: Boolean(execution.executed),
    status: execution.status || (execution.ok ? 'done' : 'blocked'),
    requiresConfirmation: Boolean(requiresConfirmation && execute && !confirmed),
    missingRequirements: execution.missingRequirements || [],
    plan,
    action,
    result: execution.result,
    approval: execution.approval,
    verification,
    output: execution.output,
  };
  const output = formatCreativeActionExecutionOutput(outputDraft);
  const workflowStatus = outputDraft.status === 'preview'
    ? 'done'
    : ['queued', 'running', 'done', 'failed', 'cancelled', 'blocked'].includes(outputDraft.status)
      ? outputDraft.status
      : 'blocked';
  const workflowDraft = {
    kind: 'creative_action',
    source: options.source || 'creative_action',
    status: workflowStatus,
    title: `Creative action · ${action.label}`.slice(0, 180),
    intent: action.id,
    mode: execute ? 'local' : 'preview',
    request: instruction,
    result: output,
    target: {
      app: plan.selectedApp?.name || '',
      appId: plan.selectedApp?.id || '',
      appDomain: plan.selectedApp?.domain || creativeWorkflowDomain(plan.intent),
      appInstalled: Boolean(plan.selectedApp?.installed),
      appPath: plan.selectedApp?.appPath || '',
      stageId: plan.focusedStage?.id || '',
      focusedStageId: plan.focusedStage?.id || '',
      actionId: action.id,
      actionCount: plan.actionPack?.actions?.length || 0,
      riskLevel: action.riskLevel,
      safeToAutoRun: action.safeToAutoRun,
      confirmationRequired: requiresConfirmation,
      verificationStatus: verification?.status || '',
      recoveryHintCount: verification?.recoveryHints?.length || 0,
      path: String(options.assetPath || options.path || ''),
      type: action.type,
    },
  };
  const workflow = options.recordWorkflow === false
    ? {
        id: '',
        ...workflowDraft,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        completedAt: Date.now(),
      }
    : createWorkflowRecord(workflowDraft);
  const routing = options.recordRouting === false || !workflow.id
    ? null
    : createRoutingRecordForWorkflow({
        workflow,
        mode: 'local',
        source: options.source || 'creative_action',
        owner: 'app',
        scope: `creative:${plan.intent}:${plan.focusedStage?.id || 'stage'}:${action.id}`,
        parallelGroup: options.parallelGroup || options.group || `creative:${plan.selectedApp?.domain || plan.intent}`,
        resultSummary: output,
      });

  return {
    ...outputDraft,
    workflow,
    routing,
    output,
  };
}

function creativeBenchmarkCaseResult({ id, label, intent, ok, result, assertions = {} }) {
  const finalOk = Boolean(ok);
  const workflow = result?.workflow || {};
  const routing = result?.routing || {};
  const selectedApp = result?.selectedApp || result?.plan?.selectedApp || {};
  const focusedStage = result?.focusedStage || result?.plan?.focusedStage || {};
  const actionPack = result?.actionPack || result?.plan?.actionPack || {};
  const action = result?.action || {};
  return {
    id,
    label,
    intent,
    ok: finalOk,
    status: finalOk ? 'pass' : 'fail',
    previewOnly: result?.executed === false || result?.status === 'preview' || result?.status === 'blocked',
    executed: Boolean(result?.executed),
    blocked: String(result?.status || '').includes('blocked'),
    confirmationRequired: Boolean(result?.requiresConfirmation || action.confirmationRequired),
    modelCall: false,
    creativeAction: false,
    workflowId: workflow.id || '',
    workflowStatus: workflow.status || '',
    routingId: routing.id || '',
    routingStatus: routing.status || '',
    app: selectedApp.name || '',
    appId: selectedApp.id || '',
    stageId: focusedStage.id || actionPack.id || '',
    actionId: action.id || '',
    assertions,
    summary: compactRecordText(result?.output || actionPack.summary || action.summary || '', 260),
  };
}

